INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-01790', 'cpa', 'cpa-moex-111-341b00dc', 'sub-cpa-07', NULL, 'single_choice', '萬。其中，100 萬中的 20萬，聽起來確實比 10個之中的 2個，更令 人印象深刻，因為我們看見了 20 萬這個龐大的數字。這種現象稱之為 「比率偏差」，有時甚至會讓人們選擇獲勝機率較小的事物。例如下面這 個實驗，受試者會看到兩個分別裝著不同玻璃珠的碗，他們必須矇起眼 睛挑出紅色的玻璃珠：', '["10個玻璃珠，9個白色，1個紅色", "100 個玻璃珠，92 個白色，8 個紅色 結果 53％的受試者誤以為 B 碗裡有更多紅色珠子，挑中機率較高而選 擇錯誤。 廣告商操控我們想法的另一種手段，就是透過深思熟慮的選擇與措 辭，呈現數字。你不妨試著翻轉以下夾雜著數字的句子，窺探其背後的 真義：「有四分之一的筆電會在二十四個月內壞掉＝有四分之三的筆電 在二十四個月後，仍能良好地運作。」透過聚焦於數學性數據的某一面， 數據提供者能誘使我們以正面或負面的態度去思考。 人們常說：數字會說話。上文提醒我們看待數據時可能存在的迷思。 請說明廣告商常用的數字策略，並依個人的經驗或觀察，思考數字所呈 現的事實及其他意義的可能性，自定標題，作文一篇。（50 分） 90510 90410", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:00+00:00", "source_pdf_sha1": "536e9b17bb88", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文）", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01791', 'cpa', 'cpa-moex-111-341b00dc', 'sub-cpa-07', NULL, 'single_choice', '公尺以外，使用的是搖尾舞動。他以實驗證明，蜜蜂的舞動如同語 言傳訊一樣，的確能將花蜜來源、份量等訊息準確地傳給其他蜜蜂。作 為第一位解釋蜜蜂舞蹈的科學家，弗里希獲得了諾貝爾獎殊榮。即使獲 得這麼重要的成就，他還認為自己的探索才剛開始，曾說：「蜜蜂就像是 一口神奇的井，你提取的水越多，就發現井裡有更多的東西可以提取」。 探索的過程，如同打開一道道祕室之門、推開一扇扇神奇之窗。 閱讀上述弗里希的故事，請以「探索」為題，作文一篇，先說明你 對弗里希的話有何體會，再結合自身的探索經驗，敘寫自己的感受與 收穫。（50 分）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:00+00:00", "source_pdf_sha1": "536e9b17bb88", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文）", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 100, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01792', 'cpa', 'cpa-moex-108-341b00dc', 'sub-cpa-07', NULL, 'single_choice', '世紀以來，科技日新月異，地域輻射廣泛，人際往來多元，新型態的 群己關係普遍受到關注。美國哈佛大學丹尼爾‧戈爾曼教授在《情感智 商》（Emotional Intelligence）一書中，將人際關係概括為五個內容，其 中有「以誠相待」的「人際互動效能」一說。當代心理治療專家維傑尼 亞‧薩蒂爾，經過醫學追蹤，積累大量臨床個案，認為現代社會的人際 關係要素，除了「控制和調整自我」之外，還需要「以誠待人」、「尊 重他人」。兩者都強調人際間「誠」的重要，與前述的「第六倫」不謀 而合。 時至今日，人人處於複雜多樣的社會網絡中，如何面對瞬息萬變的人我 互動？其中的群己倫理確實值得深思。 請以「當今社會的群我關係」為題，撰文一篇，就上文中以現代社會 裡的群己關係作為「第六倫」，以及東西方皆以「誠」作為人際往來之 道，予以評議；並參酌一己經驗與體認，詳加闡述。（50分） 90510', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:00+00:00", "source_pdf_sha1": "6ce9cef8631f", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文）", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01793', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '下列四句分屬兩副對聯，請依文意與對聯的一般原則，選出正確的選項：', '["入篋從無造孳錢", "讀書何但出青雲", "養性不需烹柴雪", "登堂盡是論文客"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01794', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '下列選項何者用字完全正確？', '["他未能準時完成工作，居然還恬不知恥，怪罪別人", "這件事情的發展相當詭譎難辨，各種說法甚霄塵上", "如果不能專心一意學習，所有異想都只是掾木求魚", "作為地方官，應該愛護平民百姓，絕不可侍寵而嬌"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01795', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '下列題辭與場合、對象配對正確的選項是：', '["熊夢徵祥－賀生子；立雪神傷－輓師長", "之子于歸－賀娶婦；貨殖流芳－輓政界", "德孚眾望－賀升遷；利用厚生－輓軍界", "妙選東牀－賀喬遷；大雅淪亡－輓學者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01796', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '《史記．魏公子列傳》：「公子為人仁而下士，士無賢不肖皆謙而禮交之。」句中 「下」字是方位名詞當動詞用，下列選項「」中詞語的用法，何者與此相同？', '["子路從而「後」，遇丈人，以杖荷蓧（《論語．微子》）", "子墨衰絰，梁弘御戎，萊駒為「右」（《左傳．僖公三十三年》）", "項王乃復引兵而「東」，至東城，乃有二十八騎（《史記．項羽本記》）", "螾無爪牙之利，筋骨之強，「上」食埃土，下飲黃泉（《荀子．勸學》）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01797', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '樊遲從遊於舞雩之下，曰：「敢問崇德、脩慝、辨惑。」子曰：「善哉問！先事後 得，非崇德與？攻其惡，無攻人之惡，非脩慝與？一朝之忿，忘其身以及其親，非 惑與？」（《論語．顏淵》） 文中孔子認為「崇德」的基礎近於下列何者？', '["只問耕耘，不問收穫", "三省吾身，不欺暗室", "先之勞之，不憂不懼", "仁民愛物，不忮不求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01798', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '趙清獻公知越州，兩浙旱蝗，米價踴貴，饑死相望。 諸州皆榜衢路，禁人增米價。公獨榜通衢，令有米者增價糶之。於是米商輻輳，米 價更賤。 根據上文，對趙清獻公最適切的論述是：', '["不能苦民所苦", "不顧百姓，圖利米商", "能逆向操作，以量制價", "能未雨綢繆，使米賤民蘇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01799', 'cpa', 'cpa-moex-102-9a386a01', 'sub-cpa-08', NULL, 'single_choice', '寇萊公……歷富貴四十年，無田園邸第。入覲則寄僧舍或僦居。在大名日，自出題 試貢士，曰〈公儀休拔園葵賦〉、〈霍將軍辭治第詩〉，此其志也。詩人魏野獻詩 曰：「有官居鼎鼐，無地起樓臺。」采詩者以為中的。虜使至大名，問公曰：「莫 是『無地起樓臺』相公否？」（《湘山野錄》卷三） 根據上文，選出敘述正確的選項：', '["寇萊公應舉時所作詩賦，即已顯現清廉之志", "寇萊公清廉儉樸之名，連外國使臣都曾聽聞", "魏野的名句，外國使臣誤認為是寇萊公之作", "魏野詩譏諷寇萊公故作儉樸，頗受時人認同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:01+00:00", "source_pdf_sha1": "8601059dd73e", "answer_pdf_sha1": "e76b12d6173c", "source_family": "moex-gov-tw", "moex": {"exam_code": "102130", "c": "803", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
